function CommonUtil.GetRoleDialogIdByLandState( landId, stateType )
    if landId == nil then return end
    local _speech = GetTableData(TableName.LandLock, landId, "speech")
    if string.IsNullOrEmpty(_speech) then return end
    local _tabSpeech = string.string2array_i(_speech, ';')
    if table.count(_tabSpeech) ~= 4 then
        return
    end
    return _tabSpeech[stateType]
end

