	local Request = CS_Resource:InstantiateAsyncId(id, 
		function (req)
			
			if req.isError then
				Logger.LogError("Load prefab error : ", resPath)
				--return
			end
			
			if req.gameObject == nil then
				Logger.LogError("Load prefab null : ", resPath)
				--return
			end
			
			if func then
				func(req)
			end
		end, presetParent)
	
	if Request == nil then
		Logger.LogError("LoadResAsync error. ", resPath)
	end
	return Request
end

