-- 获取服务器ID
local function GetServerId()
	local zoneStr = Setting:GetPublicString(SettingKeys.SERVER_ZONE, "")
	if string.IsNullOrEmpty(zoneStr) then
		Logger.LogError("GetServerId no server zone!")
		return 0
	end

	local t = string.match(zoneStr, '%d+')
	if t == nil then
		Logger.LogError("GetServerId is Wrong!!!", zoneStr)
		return 0
	end

	return math.tointeger(t)
end

