function Is(obj, typeClass)
    local is_generic = xlua.get_generic_method(CS.CommonUtils, 'Is') --取得泛型方法
    local is_func = is_generic(typeClass) --为泛型方法指定类型
    local ret = is_func(obj)

    return ret
end

function CommonUtil.PlayAnimationReturnTime(simpleAnimation, animName)
    local anim = simpleAnimation:GetState(animName)
    if anim == nil then
        return false
    end

    simpleAnimation:Play(animName)
    return true, simpleAnimation:GetClipLength(animName)
end

function List_GetFirstTypeObject(list, typeClass)
    for _, obj in pairs(list) do
        if Is(obj, typeClass) then
            return obj
        end
    end

    return nil
end

