-- 这里包一层，主要是为了防止json解析出错！而导致的程序异常情况！！
function JsonDecode(text)
	local rapidjson = require "rapidjson"
	local ok, ret = xpcall(rapidjson.decode, debug.traceback, text)
	if ok then 
		return ret
	else
		Logger.LogError("JsonDecode error: ", text)
		return {}
	end
end

