function CommonUtil.GetColorName(color,str)
    if str == nil or color == nil then
        return nil
    end
    local t = {}
    t[1] = "<color="
    t[2] = color
    t[3] = ">"
    t[4] = str
    t[5] = "</color>"
    return table.concat(t)
end

function CommonUtil.GetFreeSpeedUpBubbleIcon()
    local reBubbleInfo = {}
    local mistressId = LuaEntry.DataConfig:TryGetNum("free_build_mistress", "k1")
    if DataCenter.MistressLvTemplateManager:IsUnlock(mistressId) then
        local baseData = DataCenter.MistressLvTemplateManager:GetBaseData(mistressId)
        if baseData then
            reBubbleInfo.type = FreeTimeBubbleType.Girl
            reBubbleInfo.icon = string.format(LoadPath.GirlIconsSmall, baseData.bubblesIcon)
            reBubbleInfo.name = baseData.name
            return reBubbleInfo
        end
    else
        local hero = DataCenter.HeroDataManager:GetFreeAddTimeHero(EffectDefine.BUILD_TIME_REDUCE)
        if hero then
            reBubbleInfo.type = FreeTimeBubbleType.Hero
            reBubbleInfo.icon = HeroUtils.GetHeroIconRoundPath(hero.heroId)
            reBubbleInfo.name = hero.config.name
            return reBubbleInfo
        end
    end
    
    reBubbleInfo.type = FreeTimeBubbleType.Build
    reBubbleInfo.icon = string.format(LoadPath.ItemPath,"item200")
    reBubbleInfo.name = 100291
    return reBubbleInfo
end

