--region 位运算

---获得二进制标志位
---@public
---@param bit number
---@param index number
---@return number (0 或者 1)
function CommonUtil.GetBitFlag(bit, index)
    return (bit & (1 << index)) >> index
end

---设置二进制标志位
---@public
---@param bit number
---@param index number
---@param value number (0 或者 1)
---@return number
function CommonUtil.SetBitFlag(bit, index, value)
    local tmp = 1 << index
    if value > 0 then
        bit = bit | tmp
    else
        bit = bit & ~tmp
    end
    return bit
end

--endregion

